import { format } from "date-fns";
import { useState } from "react";
import { useGetList, useRefresh, useUpdate } from "ra-core";

import { HatchGhostButton, HatchPrimaryButton } from "../../_primitives";
import { useConfigurationContext } from "../../root/ConfigurationContext";
import type { Deal } from "../../types";

type CompanyRecord = {
  id: number;
  name: string;
};

type SalesRecord = {
  id: number | string;
  first_name: string;
  last_name: string;
};

const formatCurrency = (value: number, currency: string) =>
  value.toLocaleString(undefined, {
    style: "currency",
    currency,
    maximumFractionDigits: 0,
  });

const safeFormatDate = (value: unknown): string => {
  if (value == null || value === "") return "—";
  const d = new Date(value as string | number | Date);
  if (Number.isNaN(d.getTime())) return "—";
  try {
    return format(d, "MMM d");
  } catch {
    return "—";
  }
};

type HandoffCardProps = {
  companyName: string;
  dealName: string;
  dealValue: string;
  wonDate: string;
  salesName: string;
  onStart?: () => void;
  isUpdating?: boolean;
};

const labelStyle: React.CSSProperties = {
  fontSize: 10,
  color: "var(--fg-3)",
  letterSpacing: "0.12em",
  textTransform: "uppercase",
  fontWeight: 700,
  marginBottom: 6,
};

const metricValueStyle: React.CSSProperties = {
  fontSize: 14,
  fontWeight: 700,
  color: "var(--fg-1)",
  letterSpacing: "-0.01em",
};

const HandoffCard = ({
  companyName,
  dealName,
  dealValue,
  wonDate,
  salesName,
  onStart,
  isUpdating,
}: HandoffCardProps) => (
  <div
    style={{
      background: "var(--ink-4a)",
      border: "1px solid var(--line)",
      borderLeft: "3px solid var(--warn)",
      borderRadius: 10,
      padding: "18px 20px",
      display: "flex",
      flexDirection: "column",
      gap: 16,
      minWidth: 0,
    }}
  >
    {/* Top row: company + description, cta */}
    <div
      style={{
        display: "flex",
        alignItems: "flex-start",
        justifyContent: "space-between",
        gap: 14,
      }}
    >
      <div style={{ minWidth: 0, flex: 1 }}>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            marginBottom: 6,
          }}
        >
          <span
            style={{
              width: 7,
              height: 7,
              borderRadius: 999,
              background: "var(--good)",
              boxShadow: "0 0 8px rgba(52,211,153,0.7)",
              flexShrink: 0,
            }}
          />
          <h3
            className="font-heading"
            style={{
              margin: 0,
              fontSize: 17,
              fontWeight: 700,
              color: "var(--fg-1)",
              letterSpacing: "-0.02em",
              overflow: "hidden",
              textOverflow: "ellipsis",
              whiteSpace: "nowrap",
            }}
          >
            {companyName}
          </h3>
        </div>
        <p
          style={{
            margin: "0 0 0 17px",
            fontSize: 12.5,
            color: "var(--fg-3)",
            lineHeight: 1.45,
          }}
        >
          {dealName}
        </p>
      </div>
      <HatchPrimaryButton
        onClick={onStart}
        disabled={isUpdating || !onStart}
        size="sm"
        className="h-9 flex-shrink-0 whitespace-nowrap"
      >
        Start onboarding
      </HatchPrimaryButton>
    </div>

    {/* Metric stack */}
    <div
      style={{
        display: "grid",
        gridTemplateColumns: "repeat(3, minmax(0, 1fr))",
        gap: 10,
      }}
    >
      <div
        style={{
          padding: "10px 12px",
          borderRadius: 8,
          background: "rgba(255,255,255,0.03)",
          border: "1px solid var(--line)",
        }}
      >
        <div style={labelStyle}>Deal Value</div>
        <div className="font-mono" style={metricValueStyle}>
          {dealValue}
        </div>
      </div>
      <div
        style={{
          padding: "10px 12px",
          borderRadius: 8,
          background: "rgba(255,255,255,0.03)",
          border: "1px solid var(--line)",
        }}
      >
        <div style={labelStyle}>Won Date</div>
        <div className="font-mono" style={metricValueStyle}>
          {wonDate}
        </div>
      </div>
      <div
        style={{
          padding: "10px 12px",
          borderRadius: 8,
          background: "rgba(255,255,255,0.03)",
          border: "1px solid var(--line)",
        }}
      >
        <div style={labelStyle}>Sales</div>
        <div className="font-mono" style={metricValueStyle}>
          {salesName}
        </div>
      </div>
    </div>
  </div>
);

export const HandoffQueue = () => {
  const { currency } = useConfigurationContext();
  const refresh = useRefresh();
  const [update, { isPending: isUpdating }] = useUpdate<Deal>();
  const [expandedCard, setExpandedCard] = useState<string | number | null>(
    null,
  );
  const [projectedHoursInputs, setProjectedHoursInputs] = useState<
    Record<string | number, string>
  >({});

  const { data: deals, isPending: dealsPending } = useGetList<Deal>("deals", {
    pagination: { page: 1, perPage: 10000 },
  });

  const { data: companies, isPending: companiesPending } =
    useGetList<CompanyRecord>("companies", {
      pagination: { page: 1, perPage: 10000 },
    });

  const { data: sales, isPending: salesPending } = useGetList<SalesRecord>(
    "sales",
    { pagination: { page: 1, perPage: 100 } },
  );

  if (dealsPending || companiesPending || salesPending) {
    return null;
  }

  const companyNameById = new Map((companies ?? []).map((c) => [c.id, c.name]));
  const salesNameById = new Map(
    (sales ?? []).map((s) => [s.id, `${s.first_name} ${s.last_name}`.trim()]),
  );
  const pendingHandoffDeals =
    deals?.filter(
      (deal) => deal.stage === "won" && deal.project_status == null,
    ) ?? [];

  const handleConfirmOnboarding = (deal: Deal) => {
    const rawInput = projectedHoursInputs[deal.id] ?? "";
    const trimmed = rawInput.trim();
    const projectedHours =
      trimmed === "" ? undefined : Number.parseFloat(trimmed);

    if (trimmed !== "" && Number.isNaN(projectedHours)) {
      return;
    }

    update(
      "deals",
      {
        id: deal.id,
        data: {
          ...deal,
          project_started_at: new Date().toISOString(),
          project_status: "on_track",
          ...(projectedHours !== undefined
            ? { projected_hours: projectedHours }
            : {}),
        },
        previousData: deal,
      },
      {
        onSuccess: () => {
          setExpandedCard(null);
          setProjectedHoursInputs((prev) => {
            const next = { ...prev };
            delete next[deal.id];
            return next;
          });
          refresh();
        },
      },
    );
  };

  return (
    <section
      style={{
        borderRadius: 12,
        background: "var(--ink-3)",
        border: "1px solid var(--line)",
        overflow: "hidden",
        flexShrink: 0,
      }}
    >
      {/* Header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "16px 22px",
          borderBottom: "1px solid var(--line)",
        }}
      >
        <div>
          <div
            style={{
              fontSize: 10,
              letterSpacing: "0.22em",
              textTransform: "uppercase",
              color: "var(--warn)",
              fontWeight: 700,
              marginBottom: 4,
            }}
          >
            Handoff Queue
          </div>
          <h3
            className="font-heading"
            style={{
              margin: 0,
              fontSize: 16,
              fontWeight: 700,
              color: "var(--fg-1)",
              letterSpacing: "-0.01em",
            }}
          >
            Recently closed-won
          </h3>
        </div>
        <span
          className="font-mono"
          style={{
            fontSize: 11,
            fontWeight: 700,
            color: "var(--warn)",
            background: "rgba(245,184,74,0.1)",
            border: "1px solid rgba(245,184,74,0.25)",
            padding: "4px 10px",
            borderRadius: 5,
          }}
        >
          {pendingHandoffDeals.length} pending
        </span>
      </div>

      {/* Card grid or empty state */}
      {pendingHandoffDeals.length === 0 ? (
        <div
          style={{
            fontSize: 13,
            color: "var(--fg-3)",
            padding: 24,
            textAlign: "center",
          }}
        >
          No deals pending handoff. Win a deal in the pipeline to start a
          project here.
        </div>
      ) : (
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(320px, 1fr))",
            gap: 14,
            padding: 18,
          }}
        >
          {pendingHandoffDeals.map((deal) => {
            const companyName =
              (deal.company_id != null
                ? companyNameById.get(deal.company_id as number)
                : undefined) ?? "Unknown";
            const salesName =
              (deal.sales_id != null
                ? salesNameById.get(deal.sales_id as number | string)
                : undefined) ?? "Unassigned";
            const amountValue =
              typeof deal.amount === "number" && Number.isFinite(deal.amount)
                ? deal.amount
                : 0;
            const isExpanded = expandedCard === deal.id;
            return (
              <div
                key={deal.id}
                style={{ display: "flex", flexDirection: "column", gap: 8 }}
              >
                <HandoffCard
                  companyName={companyName}
                  dealName={deal.name ?? "Untitled deal"}
                  dealValue={formatCurrency(amountValue, currency)}
                  wonDate={safeFormatDate(deal.updated_at)}
                  salesName={salesName}
                  onStart={
                    isExpanded ? undefined : () => setExpandedCard(deal.id)
                  }
                  isUpdating={isUpdating}
                />
                {isExpanded && (
                  <div
                    style={{
                      background: "var(--ink-3)",
                      border: "1px solid rgba(255,255,255,0.1)",
                      borderRadius: 8,
                      padding: "14px 16px",
                      display: "flex",
                      flexDirection: "column",
                      gap: 10,
                    }}
                  >
                    <div
                      style={{
                        fontSize: 12,
                        color: "var(--fg-3)",
                        letterSpacing: "0.04em",
                      }}
                    >
                      Projected hours (optional)
                    </div>
                    <input
                      type="number"
                      min="0"
                      step="0.5"
                      value={projectedHoursInputs[deal.id] ?? ""}
                      onChange={(e) =>
                        setProjectedHoursInputs((prev) => ({
                          ...prev,
                          [deal.id]: e.target.value,
                        }))
                      }
                      placeholder="e.g. 120"
                      style={{
                        background: "var(--ink-4a)",
                        border: "1px solid rgba(255,255,255,0.1)",
                        borderRadius: 6,
                        padding: "8px 12px",
                        fontSize: 14,
                        color: "var(--fg-1)",
                        width: "100%",
                        boxSizing: "border-box",
                      }}
                    />
                    <div
                      style={{ display: "flex", alignItems: "center", gap: 10 }}
                    >
                      <HatchPrimaryButton
                        onClick={() => handleConfirmOnboarding(deal)}
                        disabled={isUpdating}
                        size="sm"
                      >
                        Confirm
                      </HatchPrimaryButton>
                      <HatchGhostButton
                        onClick={() => setExpandedCard(null)}
                        size="sm"
                      >
                        Cancel
                      </HatchGhostButton>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </section>
  );
};
