import { AlertCircle, DollarSign, Percent, Trophy } from "lucide-react";
import { useGetIdentity, useGetList } from "ra-core";
import { Link } from "react-router";
import { Card } from "@/components/ui/card";

import { useConfigurationContext } from "../root/ConfigurationContext";
import type { Deal, Task } from "../types";

const today = () => {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  return date;
};

const formatCurrency = (value: number, currency: string) =>
  value.toLocaleString(undefined, {
    style: "currency",
    currency,
    maximumFractionDigits: 0,
  });

type KPICardsProps = {
  variant?: "overview" | "sales";
  columns?: 2 | 4;
};

export const KPICards = ({
  variant = "overview",
  columns = 4,
}: KPICardsProps) => {
  const { currency } = useConfigurationContext();
  const { identity, isPending: identityPending } = useGetIdentity();
  const gridClass =
    columns === 2
      ? "grid grid-cols-2 gap-4"
      : "grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4";

  const { data: deals, isPending: dealsPending } = useGetList<Deal>("deals", {
    pagination: { page: 1, perPage: 10000 },
  });

  const { data: tasks, isPending: tasksPending } = useGetList<Task>(
    "tasks",
    {
      pagination: { page: 1, perPage: 10000 },
      sort: { field: "due_date", order: "ASC" },
      filter: { sales_id: identity?.id },
    },
    { enabled: identity?.id != null },
  );

  if (identityPending || dealsPending || tasksPending) {
    return (
      <div className={gridClass}>
        {Array.from({ length: 4 }).map((_, index) => (
          <div key={index} className="h-24 rounded-xl bg-muted animate-pulse" />
        ))}
      </div>
    );
  }

  const activeDeals =
    deals?.filter((deal) => !["won", "lost"].includes(deal.stage)) ?? [];
  const pipelineValue = activeDeals.reduce(
    (sum, deal) => sum + (deal.amount ?? 0),
    0,
  );
  const wonDeals = deals?.filter((deal) => deal.stage === "won") ?? [];
  const dealsWon = wonDeals.length;
  const closedDeals =
    deals?.filter((deal) => ["won", "lost"].includes(deal.stage)).length ?? 0;
  const startOfToday = today();

  const overdueTasks =
    tasks?.filter((task) => {
      if (!task.due_date || task.done_date) {
        return false;
      }

      return new Date(task.due_date) < startOfToday;
    }).length ?? 0;

  return (
    <div className={gridClass}>
      <Link to="/deals">
        <Card className="cursor-pointer gap-3 p-4 transition-all duration-150 hover:-translate-y-0.5 hover:shadow-md active:translate-y-0 active:shadow-sm">
          <DollarSign className="h-5 w-5 text-emerald-500" />
          <div className="space-y-1">
            <p className="text-sm font-medium text-muted-foreground font-heading">
              Pipeline Value
            </p>
            <p className="text-2xl font-bold">
              {formatCurrency(pipelineValue, currency)}
            </p>
            {variant === "sales" ? (
              <p className="text-xs text-muted-foreground">
                {activeDeals.length} active deals
              </p>
            ) : null}
          </div>
        </Card>
      </Link>
      <Link
        to={`/deals?filter=${encodeURIComponent(JSON.stringify({ stage: "won" }))}`}
      >
        <Card className="cursor-pointer gap-3 p-4 transition-all duration-150 hover:-translate-y-0.5 hover:shadow-md active:translate-y-0 active:shadow-sm">
          <Trophy className="h-5 w-5 text-cyan-500" />
          <div className="space-y-1">
            <p className="text-sm font-medium text-muted-foreground font-heading">
              Deals Won
            </p>
            <p className="text-2xl font-bold">{dealsWon}</p>
            {variant === "sales" ? (
              <p className="text-xs text-muted-foreground">+{dealsWon} won</p>
            ) : null}
          </div>
        </Card>
      </Link>
      <Link to="/deals">
        <Card className="cursor-pointer gap-3 p-4 transition-all duration-150 hover:-translate-y-0.5 hover:shadow-md active:translate-y-0 active:shadow-sm">
          <Percent className="h-5 w-5 text-violet-500" />
          <div className="space-y-1">
            <p className="text-sm font-medium text-muted-foreground font-heading">
              Win Rate
            </p>
            <p className="text-2xl font-bold">
              {closedDeals > 0
                ? `${Math.round((dealsWon / closedDeals) * 100)}%`
                : "\u2014"}
            </p>
            {variant === "sales" ? (
              <p className="text-xs text-muted-foreground">
                {closedDeals} closed
              </p>
            ) : null}
          </div>
        </Card>
      </Link>
      <Link to="/tasks">
        <Card className="cursor-pointer gap-3 p-4 transition-all duration-150 hover:-translate-y-0.5 hover:shadow-md active:translate-y-0 active:shadow-sm">
          <AlertCircle className="h-5 w-5 text-amber-500" />
          <div className="space-y-1">
            <p className="text-sm font-medium text-muted-foreground font-heading">
              Overdue Tasks
            </p>
            <p
              className={`text-2xl font-bold ${
                overdueTasks > 0 ? "text-destructive" : ""
              }`}
            >
              {overdueTasks}
            </p>
            {variant === "sales" ? (
              <p className="text-xs text-muted-foreground">
                {overdueTasks > 0 ? "Needs attention" : "All clear"}
              </p>
            ) : null}
          </div>
        </Card>
      </Link>
    </div>
  );
};
